const { simpleParser } = mailparserPkg;
const formatStatus = global.get('utils.formatStatus', 'initializers') || (t => t);

const { uid, message_id, gmail_label, label, envelope } = msg.payload;
const client = flow.get('imap_client', 'volatile');

if (!client || !client.usable) {
    node.warn(`Client unavailable; cannot publish UID ${uid}`);
    return null;
}

node.status({ fill: 'yellow', shape: 'ring', text: formatStatus(`Parsing UID ${uid}...`) });

(async () => {
    try {
        // Fetch the raw source for mailparser
        const { content } = await client.download(uid, '', { uid: true });

        // Collect the stream into a buffer
        const chunks = [];
        for await (const chunk of content) chunks.push(chunk);
        const rawSource = Buffer.concat(chunks);

        const parsed = await simpleParser(rawSource);

        // Build the normalized payload per EMAIL_INGRESS.md schema
        const published = {
            message_id,
            label,
            gmail_label,
            from: envelope?.from?.[0]?.address || null,
            from_name: envelope?.from?.[0]?.name || null,
            to: envelope?.to?.[0]?.address || null,
            subject: envelope?.subject || '',
            received_at: envelope?.date?.toISOString() || new Date().toISOString(),
            body_text: parsed.text || '',
            body_html: parsed.html || '',
            attachment_count: (parsed.attachments || []).length
        };

        // Record in pending-ACK map for later archival on ACK receipt
        const pending = flow.get('imap_pending_ack') || {};
        pending[message_id] = {
            uid,
            gmail_label,
            published_at: Date.now()
        };
        flow.set('imap_pending_ack', pending);

        // Emit MQTT-ready msg
        node.send({
            topic: `highland/event/email/${label}/received`,
            payload: published,
            retain: false,
            qos: 1
        });

        node.status({
            fill: 'green',
            shape: 'dot',
            text: formatStatus(`Published UID ${uid} (${label})`)
        });
    } catch (err) {
        node.status({ fill: 'red', shape: 'ring', text: formatStatus(`Parse failed: ${err.message}`) });
        node.warn(`Failed to parse/publish UID ${uid}: ${err.message}`);
    }
})();

return null;

const formatStatus = global.get('utils.formatStatus', 'initializers') || (t => t);

const messageId = msg.payload?.message_id;
if (!messageId) {
    node.warn(`No message_id on incoming msg; passing through (UID ${msg.payload?.uid})`);
    node.status({ fill: 'yellow', shape: 'ring', text: formatStatus('Missing message_id') });
    return msg;
}

const dedupKey = `imap_seen_${messageId}`;
const existing = flow.get(dedupKey);

if (existing) {
    const ageSec = Math.floor((Date.now() - existing.seen_at) / 1000);
    node.status({ fill: 'yellow', shape: 'ring', text: formatStatus(`Duplicate (age ${ageSec}s)`) });
    node.warn(`DEDUP: dropping duplicate message_id=${messageId} (previously seen ${ageSec}s ago, uid=${existing.uid})`);
    return null; // drop
}

// Mark seen
flow.set(dedupKey, {
    seen_at: Date.now(),
    uid: msg.payload.uid,
    gmail_label: msg.payload.gmail_label
});

node.status({ fill: 'green', shape: 'dot', text: formatStatus(`New: ${messageId.slice(0, 30)}...`) });
return msg;

const formatStatus = global.get('utils.formatStatus', 'initializers') || (t => t);

// Parse the ACK payload
let ack;
try {
    ack = typeof msg.payload === 'string' ? JSON.parse(msg.payload) : msg.payload;
} catch (err) {
    node.warn(`Malformed ACK payload: ${err.message}`);
    node.status({ fill: 'red', shape: 'ring', text: formatStatus('Malformed ACK') });
    return null;
}

const { message_id, consumer, status } = ack || {};

if (!message_id || !status) {
    node.warn(`ACK missing required fields (message_id, status): ${JSON.stringify(ack)}`);
    node.status({ fill: 'red', shape: 'ring', text: formatStatus('Invalid ACK shape') });
    return null;
}

// Look up the in-flight entry
const pending = flow.get('imap_pending_ack') || {};
const entry = pending[message_id];

if (!entry) {
    // Not tracking this one — either already processed, or never ours
    node.warn(`ACK for unknown message_id ${message_id} from consumer ${consumer} (status=${status})`);
    node.status({ fill: 'yellow', shape: 'ring', text: formatStatus('Unknown message_id') });
    return null;
}

// Dispatch by status
if (status === 'ok' || status === 'rejected') {
    // Normal path: archive the message
    node.status({
        fill: 'green',
        shape: 'dot',
        text: formatStatus(`ACK ${status} for UID ${entry.uid}`)
    });

    // Remove from pending-ack map
    delete pending[message_id];
    flow.set('imap_pending_ack', pending);

    // Emit to Archive Message (output 1)
    return [{
        payload: {
            uid: entry.uid,
            gmail_label: entry.gmail_label,
            message_id,
            consumer,
            ack_status: status
        }
    }, null];
}

if (status === 'parse_error') {
    // Parser failure path: increment retry counter, don't archive
    const retryKey = `imap_retries_${message_id}`;
    const retries = (flow.get(retryKey) || 0) + 1;
    flow.set(retryKey, retries);

    const threshold = 3; // TODO: read from config when we wire it
    node.warn(`parse_error from ${consumer} for message_id ${message_id} (retry ${retries}/${threshold})`);
    node.status({
        fill: 'red',
        shape: 'ring',
        text: formatStatus(`parse_error retry ${retries}`)
    });

    return [null, {
        payload: {
            message_id,
            consumer,
            retries,
            threshold_reached: retries >= threshold,
            uid: entry.uid,
            gmail_label: entry.gmail_label
        }
    }];
}

// Unknown status
node.warn(`ACK with unknown status "${status}" for message_id ${message_id}`);
node.status({ fill: 'red', shape: 'ring', text: formatStatus(`Unknown status: ${status}`) });
return null;

const formatStatus = global.get('utils.formatStatus', 'initializers') || (t => t);
const PROCESSED_LABEL = 'Highland/Processed';
const LABEL_PREFIX = 'Highland/';

const { uid, gmail_label, message_id, consumer, ack_status } = msg.payload;
const client = flow.get('imap_client', 'volatile');

if (!client || !client.usable) {
    node.warn(`Client unavailable; cannot archive UID ${uid}`);
    node.status({ fill: 'red', shape: 'ring', text: formatStatus('No client') });
    return null;
}

node.status({ fill: 'yellow', shape: 'ring', text: formatStatus(`Archiving UID ${uid}...`) });

(async () => {
    try {
        // Apply Highland/Processed
        await client.messageFlagsAdd(uid, [PROCESSED_LABEL], { uid: true, useLabels: true });

        // Remove the source Highland label
        // Defensive check guards against removing Highland/Processed itself in edge cases
        if (gmail_label && gmail_label !== PROCESSED_LABEL && gmail_label.startsWith(LABEL_PREFIX)) {
            await client.messageFlagsRemove(uid, [gmail_label], { uid: true, useLabels: true });
        }

        node.status({
            fill: 'green',
            shape: 'dot',
            text: formatStatus(`Archived UID ${uid}`)
        });
        node.warn(`Archived UID ${uid}: +${PROCESSED_LABEL}, -${gmail_label} (consumer=${consumer}, status=${ack_status})`);

        node.send({
            payload: {
                uid,
                message_id,
                applied: PROCESSED_LABEL,
                removed: gmail_label,
                consumer,
                ack_status,
                archived_at: new Date().toISOString()
            }
        });
    } catch (err) {
        node.status({ fill: 'red', shape: 'ring', text: formatStatus(`Archive failed: ${err.message}`) });
        node.warn(`Failed to archive UID ${uid}: ${err.message}`);
    }
})();

return null;

const formatStatus = global.get('utils.formatStatus', 'initializers') || (t => t);

// Emulate what Utility: Deliveries would do: receive the published email,
// pretend to process it, publish an ACK.
const published = msg.payload;

if (!published?.message_id) {
    node.warn('Mock consumer received msg without message_id');
    node.status({ fill: 'red', shape: 'ring', text: formatStatus('Missing message_id') });
    return null;
}

const shortId = published.message_id.slice(0, 30);
node.status({
    fill: 'green',
    shape: 'dot',
    text: formatStatus(`Mock ACK for ${shortId}...`)
});

return {
    topic: 'highland/ack/email',
    payload: {
        message_id: published.message_id,
        consumer: 'mock_test_consumer',
        processed_at: new Date().toISOString(),
        status: 'ok'
    },
    qos: 1,
    retain: false
};
